import{_ as r,o as t,c as a,ae as e}from"./chunks/framework.BzQXgbNp.js";const u=JSON.parse('{"title":"🤖 Discord 機器人連動與雙向控制指南","description":"","frontmatter":{},"headers":[],"relativePath":"Discord-Integration.md","filePath":"Discord-Integration.md"}'),i={name:"Discord-Integration.md"};function n(s,o,l,d,c,g){return t(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="🤖-discord-機器人連動與雙向控制指南" tabindex="-1">🤖 Discord 機器人連動與雙向控制指南 <a class="header-anchor" href="#🤖-discord-機器人連動與雙向控制指南" aria-label="Permalink to &quot;🤖 Discord 機器人連動與雙向控制指南&quot;">​</a></h1><p>Craft-Core 配備了強大的 <strong>Discord 雙向連動機器人</strong>。玩家與管理員可直接在專屬頻道中點選按鈕、使用選單與提交 Modal 表單，與遊戲伺服器進行即時的資料互通與自動化管理。</p><hr><h2 id="_1-🔑-帳號雙向綁定" tabindex="-1">1. 🔑 帳號雙向綁定 <a class="header-anchor" href="#_1-🔑-帳號雙向綁定" aria-label="Permalink to &quot;1. 🔑 帳號雙向綁定&quot;">​</a></h2><p>使用機器人的個人化功能前，請先完成 Discord 帳號與 Minecraft 遊戲角色的綁定：</p><ol><li><strong>獲取驗證碼</strong>：在 Minecraft 遊戲中輸入 <strong><code>/discord link</code></strong>，系統會隨機生成一組 <strong>6 位數字驗證碼</strong>（例如：<code>654321</code>）。</li><li><strong>傳送給機器人</strong>：在 Discord 中私訊本伺服器機器人，直接發送該 6 位數字。</li><li><strong>完成綁定</strong>：機器人驗證成功後回傳綁定成功訊息。 <ul><li><em>解除綁定</em>：在 Discord 中輸入指令 <strong><code>/解除綁定</code></strong>。</li></ul></li></ol><hr><h2 id="_2-📺-5-大-discord-專屬控制面板頻道" tabindex="-1">2. 📺 5 大 Discord 專屬控制面板頻道 <a class="header-anchor" href="#_2-📺-5-大-discord-專屬控制面板頻道" aria-label="Permalink to &quot;2. 📺 5 大 Discord 專屬控制面板頻道&quot;">​</a></h2><p>機器人會在以下 5 個專屬頻道中自動維護與編輯互動面板：</p><h3 id="🔑-a-鑰匙與簽到系統-頻道-1524920698001297518" tabindex="-1">🔑 A. 鑰匙與簽到系統 (頻道 <code>1524920698001297518</code>) <a class="header-anchor" href="#🔑-a-鑰匙與簽到系統-頻道-1524920698001297518" aria-label="Permalink to &quot;🔑 A. 鑰匙與簽到系統 (頻道 `1524920698001297518`)&quot;">​</a></h3><ul><li><strong>📅 每日簽到</strong>：點選按鈕完成當日簽到，隨機獲得道具與 <strong>$150 遊戲金幣</strong>。</li><li><strong>🎰 幸運抽獎</strong>：消耗抽獎鑰匙進行抽獎，保底獲得 <strong>$150 金幣</strong>。</li><li><strong>🔑 查詢鑰匙</strong>：即時查詢您擁有的鑰匙數量與簽到連續天數。</li><li><strong>🏆 簽到排行榜</strong>：查看伺服器連續簽到與總簽到天數排行榜。</li><li><strong>🔔 訂閱提醒</strong>：訂閱簽到重置私訊提醒。</li><li><strong>⏳ 時數兌換</strong>：將累積的遊戲在線時數兌換為抽獎鑰匙。</li></ul><h3 id="📦-b-玩家快遞與收件箱-頻道-1524368641993474189" tabindex="-1">📦 B. 玩家快遞與收件箱 (頻道 <code>1524368641993474189</code>) <a class="header-anchor" href="#📦-b-玩家快遞與收件箱-頻道-1524368641993474189" aria-label="Permalink to &quot;📦 B. 玩家快遞與收件箱 (頻道 `1524368641993474189`)&quot;">​</a></h3><ul><li><strong>📦 寄送快遞</strong>：遠端將背包中的物品寄給其他線上或離線玩家。</li><li><strong>💰 寄送金幣</strong>：遠端轉帳遊戲金幣給其他玩家。</li><li><strong>📬 查詢收件箱</strong>：即時查詢您收到的待領取包裹與款項。</li></ul><h3 id="🏦-c-經濟與商店控制台-頻道-1525341244895531018" tabindex="-1">🏦 C. 經濟與商店控制台 (頻道 <code>1525341244895531018</code>) <a class="header-anchor" href="#🏦-c-經濟與商店控制台-頻道-1525341244895531018" aria-label="Permalink to &quot;🏦 C. 經濟與商店控制台 (頻道 `1525341244895531018`)&quot;">​</a></h3><ul><li><strong>💰 查詢餘額</strong>：即時回傳您角色的金幣餘額。</li><li><strong>🏪 我的商店數據</strong>：列出您名下所有箱子商店的位置、商品、單價與庫存。</li><li><strong>🏆 伺服器富豪榜</strong>：顯示全服金幣餘額前 10 名的玩家。</li></ul><h3 id="📍-d-公共傳送點與設施審核-頻道-1524354515661492344" tabindex="-1">📍 D. 公共傳送點與設施審核 (頻道 <code>1524354515661492344</code>) <a class="header-anchor" href="#📍-d-公共傳送點與設施審核-頻道-1524354515661492344" aria-label="Permalink to &quot;📍 D. 公共傳送點與設施審核 (頻道 `1524354515661492344`)&quot;">​</a></h3><ul><li><strong>✨ 現有公共傳送點列表</strong>：動態展示現有 <code>/warp</code> 地標清單與座標。</li><li><strong>📝 提交公共設施 / Warp 審核按鈕</strong>：點擊開啟 Modal 表單，填寫設施名稱、功能說明與座標，提交給管理員審核。</li></ul><h3 id="🚫-e-管理員控制面板-頻道-1524977578362933419" tabindex="-1">🚫 E. 管理員控制面板 (頻道 <code>1524977578362933419</code>) <a class="header-anchor" href="#🚫-e-管理員控制面板-頻道-1524977578362933419" aria-label="Permalink to &quot;🚫 E. 管理員控制面板 (頻道 `1524977578362933419`)&quot;">​</a></h3><ul><li><strong>🚫 封鎖玩家</strong> / <strong>🥾 踢出玩家</strong>：彈出 Modal 輸入 ID 與理由，自動發送 <code>/ban</code> 或 <code>/kick</code>。</li><li><strong>🤝 聯名獎勵</strong>：給予指定玩家 <strong>$5,000 金幣 + 6 把抽獎鑰匙</strong>。</li><li><strong>🔍 查詢玩家</strong>：調閱玩家餘額、線上/離線狀態、座標、TPS 與背包物品。</li><li><strong>📢 發布全服公告</strong>：預覽並於遊戲內發送全服彩色廣播。</li><li><strong>📍 公共設施 Warp 審核卡片</strong>：接收玩家提交的設施審核卡片，提供 <code>✅ 同意通過</code>（自動建立 <code>/warp</code> 點）與 <code>❌ 駁回</code> 按鈕。</li></ul><hr><h2 id="📜-3-交易即時推播頻道" tabindex="-1">📜 3. 交易即時推播頻道 <a class="header-anchor" href="#📜-3-交易即時推播頻道" aria-label="Permalink to &quot;📜 3. 交易即時推播頻道&quot;">​</a></h2><p>只要遊戲內有任何箱子商店成交，伺服器就會即時將交易詳情（買家、賣家、商品、單價、交易數量與印花稅）發送至指定的交易日誌頻道，讓玩家在 Discord 即可掌握伺服器物價波動！</p>',22)])])}const _=r(i,[["render",n]]);export{u as __pageData,_ as default};
